import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../../api/api";

// ✅ MASTER CATEGORIES — exact same values as PostProject & FindProjects
const CATEGORIES = [
  { value: "web-development",     label: "Web Development"    },
  { value: "mobile-development",  label: "Mobile Development" },
  { value: "ui-ux-design",        label: "UI/UX Design"       },
  { value: "graphic-design",      label: "Graphic Design"     },
  { value: "backend-development", label: "Backend Development"},
  { value: "data-science",        label: "Data Science & ML"  },
  { value: "devops-cloud",        label: "DevOps / Cloud"     }, // ✅ "devops-cloud" not "devops"
  { value: "content-writing",     label: "Content Writing"    },
  { value: "digital-marketing",   label: "Digital Marketing"  },
  { value: "video-editing",       label: "Video Editing"      },
  { value: "seo",                 label: "SEO"                },
  { value: "cybersecurity",       label: "Cybersecurity"      },
  { value: "other",               label: "Other"              },
];

const getCategoryLabel = (value) =>
  CATEGORIES.find(c => c.value === value)?.label || value || "Other";

const formatDate = (d) => {
  if (!d) return "";
  return new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
};

const MyProjects = () => {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading]   = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    API.get("/projects/client")
      .then(res => setProjects(res.data || []))
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", minHeight:"100vh", background:"#f8fafc" }}>
      <div style={{ width:32, height:32, border:"3px solid #e2e8f0", borderTopColor:"#14b8a6", borderRadius:"50%" }} />
    </div>
  );

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px 40px", fontFamily:"'Segoe UI',sans-serif" }}>
      <div style={{ maxWidth:"860px", margin:"0 auto" }}>

        {/* HEADER */}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:6 }}>
          <div>
            <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>My Projects</h1>
            <p style={{ fontSize:"13px", color:"#64748b", margin:0 }}>{projects.length} projects posted</p>
          </div>
          <button onClick={() => navigate("/client/post-project")}
            style={{ padding:"10px 18px", borderRadius:"10px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"13px", fontWeight:"700", cursor:"pointer", display:"flex", alignItems:"center", gap:6 }}>
            + Post New Project
          </button>
        </div>

        <div style={{ marginTop:24 }}>
          {projects.length === 0 ? (
            <div style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"14px", padding:"60px", textAlign:"center" }}>
              <p style={{ color:"#94a3b8", margin:"0 0 16px" }}>No projects posted yet.</p>
              <button onClick={() => navigate("/client/post-project")}
                style={{ padding:"10px 20px", borderRadius:"9px", border:"none", background:"#0f766e", color:"white", fontSize:"13px", fontWeight:"600", cursor:"pointer" }}>
                Post your first project
              </button>
            </div>
          ) : (
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              {projects.map(p => (
                <div key={p.id} style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"14px", padding:"22px 24px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>

                  {/* TITLE + STATUS */}
                  <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:6 }}>
                    <h3 style={{ fontSize:"16px", fontWeight:"700", color:"#0f172a", margin:0 }}>{p.title}</h3>
                    <span style={{
                      padding:"2px 10px", borderRadius:20, fontSize:10, fontWeight:700, textTransform:"uppercase",
                      background: p.status==="open" ? "#dcfce7" : p.status==="in-progress" ? "#dbeafe" : p.status==="completed" ? "#f1f5f9" : "#dcfce7",
                      color:      p.status==="open" ? "#15803d" : p.status==="in-progress" ? "#1d4ed8" : p.status==="completed" ? "#475569" : "#15803d",
                    }}>
                      {p.status || "open"}
                    </span>
                  </div>

                  <p style={{ fontSize:"13px", color:"#64748b", margin:"0 0 10px", lineHeight:1.5 }}>
                    {p.description?.slice(0, 110)}...
                  </p>

                  {/* META */}
                  <div style={{ display:"flex", gap:14, flexWrap:"wrap", alignItems:"center", marginBottom:10 }}>
                    <span style={{ fontSize:"13px", fontWeight:"700", color:"#0f172a" }}>
                      💰 ₹{Number(p.budget).toLocaleString()}
                    </span>
                    {p.deadline && (
                      <span style={{ fontSize:"13px", color:"#64748b", display:"flex", alignItems:"center", gap:4 }}>
                        📅 {formatDate(p.deadline)}
                      </span>
                    )}
                    {/* ✅ getCategoryLabel maps "web-development" → "Web Development" */}
                    <span style={{ background:"#f0fdfa", color:"#0f766e", border:"1px solid #99f6e4", padding:"2px 10px", borderRadius:20, fontSize:11, fontWeight:700 }}>
                      {getCategoryLabel(p.category)}
                    </span>
                  </div>

                  {/* SKILLS */}
                  {p.skills && (
                    <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:12 }}>
                      {p.skills.split(",").map((s, i) => (
                        <span key={i} style={{ background:"#f8fafc", color:"#475569", border:"1px solid #e2e8f0", borderRadius:6, padding:"2px 8px", fontSize:11, fontWeight:600 }}>
                          {s.trim()}
                        </span>
                      ))}
                    </div>
                  )}

                  {/* ACTION BUTTONS */}
                  <div style={{ borderTop:"1px solid #f1f5f9", paddingTop:14, display:"flex", gap:10 }}>
                    <button onClick={() => navigate(`/client/projects/${p.id}/proposals`)}
                      style={{ display:"flex", alignItems:"center", gap:6, padding:"8px 16px", borderRadius:8, border:"none", background:"#0f766e", color:"white", fontSize:12, fontWeight:700, cursor:"pointer" }}>
                      📄 View Proposals
                    </button>
                    <button onClick={() => navigate(`/client/projects/${p.id}/submissions`)}
                      style={{ display:"flex", alignItems:"center", gap:6, padding:"8px 16px", borderRadius:8, border:"none", background:"#6366f1", color:"white", fontSize:12, fontWeight:700, cursor:"pointer" }}>
                      📤 Submissions
                    </button>
                    <button onClick={() => navigate(`/client/projects/${p.id}/milestones`)}
                      style={{ display:"flex", alignItems:"center", gap:6, padding:"8px 16px", borderRadius:8, border:"none", background:"#f59e0b", color:"white", fontSize:12, fontWeight:700, cursor:"pointer" }}>
                      🎯 Milestones
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default MyProjects;
